import { test } from "bun:test";
import assert from "node:assert/strict";
import { actionRetryDelay, createActionClient, MAX_ACTION_RETRIES, SpaceActionError, spaceQueryClient, } from "./client";
import { z } from "./index";
const requestSchema = z.object({});
const responseSchema = z.object({});
test("createActionClient refreshes auth and retries refreshable failures once", async () => {
    const messages = [];
    const listeners = [];
    const originalWindow = globalThis.window;
    const parentWindow = {
        postMessage(message) {
            messages.push(message);
            const requestId = typeof message === "object" && message != null
                ? message.requestId
                : null;
            globalThis.setTimeout(() => {
                for (const listener of listeners) {
                    listener({
                        source: parentWindow,
                        data: {
                            type: "hatch:space-action-auth-refresh-result",
                            requestId,
                            ok: true,
                            iframeSrc: "https://example.test/index.html?viewer_assertion=fresh-viewer",
                        },
                    });
                }
            }, 0);
        },
    };
    Object.defineProperty(globalThis, "window", {
        configurable: true,
        value: {
            parent: parentWindow,
            postMessage() { },
            addEventListener(type, listener) {
                if (type === "message") {
                    listeners.push(listener);
                }
            },
            removeEventListener(type, listener) {
                if (type !== "message") {
                    return;
                }
                const index = listeners.indexOf(listener);
                if (index >= 0) {
                    listeners.splice(index, 1);
                }
            },
            clearTimeout: globalThis.clearTimeout,
            setTimeout: globalThis.setTimeout,
        },
    });
    try {
        const actionUrls = [];
        const fetchImpl = (async (input) => {
            actionUrls.push(String(input));
            if (actionUrls.length === 1) {
                return new Response(JSON.stringify({
                    error: {
                        code: "credential_stale",
                        refreshable: true,
                    },
                    authRefreshRequired: true,
                }), { status: 401 });
            }
            return Response.json({ data: {} });
        });
        const api = createActionClient({
            endpoint: "/actions",
            fetch: fetchImpl,
        });
        await api.runInference({});
        assert.equal(actionUrls.length, 2);
        assert.equal(actionUrls[0], "/actions");
        assert.match(actionUrls[1] ?? "", /viewer_assertion=fresh-viewer/);
        assert.equal(messages.length, 1);
        assert.deepEqual(messages[0], {
            type: "hatch:space-action-auth-refresh-required",
            reason: "credential_stale",
            requestId: messages[0].requestId,
        });
        assert.match(messages[0].requestId, /^refresh-/);
    }
    finally {
        Object.defineProperty(globalThis, "window", {
            configurable: true,
            value: originalWindow,
        });
    }
});
test("createActionClient does not retry without a fresh viewer assertion", async () => {
    const listeners = [];
    const originalWindow = globalThis.window;
    const parentWindow = {
        postMessage(message) {
            const requestId = typeof message === "object" && message != null
                ? message.requestId
                : null;
            globalThis.setTimeout(() => {
                for (const listener of listeners) {
                    listener({
                        source: parentWindow,
                        data: {
                            type: "hatch:space-action-auth-refresh-result",
                            requestId,
                            ok: true,
                            iframeSrc: "https://example.test/index.html",
                        },
                    });
                }
            }, 0);
        },
    };
    Object.defineProperty(globalThis, "window", {
        configurable: true,
        value: {
            parent: parentWindow,
            addEventListener(type, listener) {
                if (type === "message") {
                    listeners.push(listener);
                }
            },
            removeEventListener(type, listener) {
                if (type !== "message") {
                    return;
                }
                const index = listeners.indexOf(listener);
                if (index >= 0) {
                    listeners.splice(index, 1);
                }
            },
            clearTimeout: globalThis.clearTimeout,
            setTimeout: globalThis.setTimeout,
        },
    });
    try {
        let actionCount = 0;
        const fetchImpl = (async () => {
            actionCount += 1;
            return new Response(JSON.stringify({
                error: {
                    code: "credential_stale",
                    refreshable: true,
                },
                authRefreshRequired: true,
            }), { status: 401 });
        });
        const api = createActionClient({
            endpoint: "/actions",
            fetch: fetchImpl,
        });
        await assert.rejects(() => api.runInference({}), /auth refresh did not return a fresh viewer_assertion/);
        assert.equal(actionCount, 1);
    }
    finally {
        Object.defineProperty(globalThis, "window", {
            configurable: true,
            value: originalWindow,
        });
    }
});
test("createActionClient throws SpaceActionError carrying the HTTP status", async () => {
    const fetchImpl = (async () => new Response(JSON.stringify({ error: "deferred_queue_full" }), {
        status: 503,
    }));
    const api = createActionClient({
        endpoint: "/actions",
        fetch: fetchImpl,
    });
    await assert.rejects(() => api.runInference({}), (error) => {
        assert.ok(error instanceof SpaceActionError);
        assert.equal(error.status, 503);
        return true;
    });
});
test("spaceQueryClient retries backpressure/transient with a bound, never permanent 4xx", () => {
    const retry = spaceQueryClient.getDefaultOptions().queries?.retry;
    assert.equal(typeof retry, "function");
    const decide = retry;
    // Backpressure (429/503) and transient server/network errors ARE retried —
    // with backoff+jitter (actionRetryDelay) — up to MAX_ACTION_RETRIES. Giving
    // up would just push the retries to an uncontrolled (un-jittered) layer.
    for (const err of [
        new SpaceActionError("overloaded", 503),
        new SpaceActionError("rate limited", 429),
        new SpaceActionError("server error", 500),
        new Error("network down"),
    ]) {
        assert.equal(decide(0, err), true);
        assert.equal(decide(MAX_ACTION_RETRIES - 1, err), true);
        assert.equal(decide(MAX_ACTION_RETRIES, err), false);
    }
    // Permanent client errors are never retried — an identical retry can't fix.
    for (const status of [400, 401, 403, 404, 422]) {
        assert.equal(decide(0, new SpaceActionError("permanent", status)), false);
    }
});
test("actionRetryDelay backs off with jitter and honors Retry-After as a floor", () => {
    // No Retry-After: full jitter within [0, exponential ceiling].
    for (let n = 0; n < 6; n++) {
        const delay = actionRetryDelay(n, new Error("transient"));
        const ceiling = Math.min(30_000, 1000 * 2 ** n);
        assert.ok(delay >= 0 && delay <= ceiling, `delay ${delay} within [0, ${ceiling}]`);
    }
    // Retry-After floor: never wait less than the server asked.
    const delay = actionRetryDelay(0, new SpaceActionError("busy", 503, 5_000));
    assert.ok(delay >= 5_000, `delay ${delay} respects the 5000ms Retry-After floor`);
});
test("createActionClient surfaces Retry-After on SpaceActionError", async () => {
    const fetchImpl = (async () => new Response(JSON.stringify({ error: "deferred_queue_full" }), {
        status: 503,
        headers: { "retry-after": "2" },
    }));
    const api = createActionClient({
        endpoint: "/actions",
        fetch: fetchImpl,
    });
    await assert.rejects(() => api.runInference({}), (error) => {
        assert.ok(error instanceof SpaceActionError);
        assert.equal(error.status, 503);
        assert.equal(error.retryAfterMs, 2_000);
        return true;
    });
});
test("createActionClient does not latch or notify the host for generic 404s", async () => {
    const messages = [];
    const originalWindow = globalThis.window;
    const parentWindow = {
        postMessage(message) {
            messages.push(message);
        },
    };
    Object.defineProperty(globalThis, "window", {
        configurable: true,
        value: {
            parent: parentWindow,
            setTimeout: globalThis.setTimeout,
        },
    });
    try {
        let actionCount = 0;
        const fetchImpl = (async () => {
            actionCount += 1;
            return new Response(JSON.stringify({
                ok: false,
                error: {
                    code: "not_found",
                    message: "space source directory was not found",
                },
            }), { status: 404 });
        });
        const api = createActionClient({
            endpoint: "/actions",
            fetch: fetchImpl,
        });
        await assert.rejects(() => api.runInference({}), SpaceActionError);
        await assert.rejects(() => api.runInference({}), SpaceActionError);
        assert.equal(actionCount, 2);
        assert.deepEqual(messages, []);
    }
    finally {
        Object.defineProperty(globalThis, "window", {
            configurable: true,
            value: originalWindow,
        });
    }
});
test("createActionClient notifies the host once and stops posting after space_unavailable", async () => {
    const messages = [];
    const originalWindow = globalThis.window;
    const parentWindow = {
        postMessage(message) {
            messages.push(message);
        },
    };
    Object.defineProperty(globalThis, "window", {
        configurable: true,
        value: {
            parent: parentWindow,
            setTimeout: globalThis.setTimeout,
        },
    });
    try {
        let actionCount = 0;
        const fetchImpl = (async () => {
            actionCount += 1;
            return new Response(JSON.stringify({
                ok: false,
                error: {
                    code: "space_unavailable",
                    message: "space source directory was not found",
                },
            }), { status: 404 });
        });
        const api = createActionClient({
            endpoint: "/actions",
            fetch: fetchImpl,
        });
        await assert.rejects(() => api.runInference({}), (error) => {
            assert.ok(error instanceof SpaceActionError);
            assert.equal(error.status, 404);
            assert.equal(error.message, "Space is no longer available");
            return true;
        });
        assert.equal(actionCount, 1);
        assert.equal(messages.length, 1);
        assert.deepEqual(messages[0], {
            type: "hatch:space-unavailable",
            reason: "space_unavailable",
            actionCallId: messages[0].actionCallId,
        });
        assert.ok(messages[0].actionCallId.length > 0);
        await assert.rejects(() => api.runInference({}), (error) => {
            assert.ok(error instanceof SpaceActionError);
            assert.equal(error.status, 404);
            assert.equal(error.message, "Space is no longer available");
            return true;
        });
        assert.equal(actionCount, 1);
        assert.equal(messages.length, 1);
    }
    finally {
        Object.defineProperty(globalThis, "window", {
            configurable: true,
            value: originalWindow,
        });
    }
});
